INSERT INTO `disease_case` (`id`, `user_id`, `prediction_record_id`, `image_filename`, `image_url`, `predicted_label`, `confirmed_label`, `crop_name`, `disease_name`, `health_status`, `confidence`, `status`, `diagnostic_summary`, `advice_json`, `evidence_json`, `created_at`, `updated_at`, `province`, `city`, `district`, `region_code`, `lat`, `lng`) VALUES (1, 12, 1, '2910540c754941278275344917af5972.JPG', '/api/static/uploads/2910540c754941278275344917af5972.JPG', 'Apple___Apple_scab', 'Apple___Apple_scab', 'Apple', 'Apple scab', 'diseased', 0.997473, 'confirmed', '当前图像更接近 Apple - Apple scab，模型置信度约 99.7%。', '{"summary": "当前图像更接近 Apple - Apple scab，模型置信度约 99.7%。", "citations": [{"title": "Apple - Apple scab 识别要点", "evidence_id": "K1", "source_name": "PlantCare 农业知识库"}, {"title": "Apple - Apple scab 初步处置", "evidence_id": "K2", "source_name": "PlantCare 农业知识库"}, {"title": "Apple - Black rot 识别要点", "evidence_id": "K4", "source_name": "PlantCare 农业知识库"}], "follow_up": "当前暂无足够相似的已确认病例，建议缩短复查周期。", "condition_overview": "Apple 疑似出现 Apple scab，当前建议以隔离、环境控制和复查为主。", "uncertainty_notice": "暂无已确认相似病例可交叉参考。", "recommended_actions": ["先把疑似 Apple scab 的叶片或植株与周边健康植株隔离观察，减少交叉传播风险。", "短期内优先调整通风、湿度和灌溉方式，避免叶面长时间潮湿。", "保留病斑扩散记录与环境信息，必要时结合人工复核再决定具体用药或处理方案。"]}', '[{"url": "", "score": 1.05, "title": "Apple - Apple scab 识别要点", "snippet": "Apple 出现 Apple scab 时，通常需要重点检查病斑扩展速度、是否伴随叶缘坏死、叶背霉层、卷曲或颜色失真，并与近期湿度、温度和灌溉情况一起判断。", "evidence_id": "K1", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 1.05, "title": "Apple - Apple scab 初步处置", "snippet": "建议先隔离疑似叶片，降低叶面持续潮湿时间，暂停过度喷施叶面肥，并记录拍摄日期、地块条件和扩散范围，为后续复查或人工复核提供依据。", "evidence_id": "K2", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.45, "title": "Apple - Black rot 识别要点", "snippet": "Apple 出现 Black rot 时，通常需要重点检查病斑扩展速度、是否伴随叶缘坏死、叶背霉层、卷曲或颜色失真，并与近期湿度、温度和灌溉情况一起判断。", "evidence_id": "K4", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.45, "title": "Apple - Black rot 初步处置", "snippet": "建议先隔离疑似叶片，降低叶面持续潮湿时间，暂停过度喷施叶面肥，并记录拍摄日期、地块条件和扩散范围，为后续复查或人工复核提供依据。", "evidence_id": "K5", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}]', '2026-03-18 15:49:45', '2026-03-18 15:49:45', NULL, NULL, NULL, '未知区域', NULL, NULL);
