INSERT INTO `disease_case` (`id`, `user_id`, `prediction_record_id`, `image_filename`, `image_url`, `predicted_label`, `confirmed_label`, `crop_name`, `disease_name`, `health_status`, `confidence`, `status`, `diagnostic_summary`, `advice_json`, `evidence_json`, `created_at`, `updated_at`, `province`, `city`, `district`, `region_code`, `lat`, `lng`) VALUES (5, 12, 5, 'f41cd5a5292e4b75b6b23c1415d92bc8.JPG', '/api/static/uploads/f41cd5a5292e4b75b6b23c1415d92bc8.JPG', 'Soybean___healthy', 'Soybean___healthy', 'Soybean', 'healthy', 'healthy', 0.993312, 'confirmed', '当前图像更接近 Soybean - healthy，模型置信度约 99.3%。', '{"summary": "当前图像更接近 Soybean - healthy，模型置信度约 99.3%。", "citations": [{"title": "Soybean - healthy 养护提示", "evidence_id": "K59", "source_name": "PlantCare 农业知识库"}, {"title": "Soybean 健康复查建议", "evidence_id": "K60", "source_name": "PlantCare 农业知识库"}, {"title": "Apple - healthy 养护提示", "evidence_id": "K10", "source_name": "PlantCare 农业知识库"}], "follow_up": "当前暂无足够相似的已确认病例，建议缩短复查周期。", "condition_overview": "Soybean 当前更接近健康状态，建议重点做持续监测，而不是直接按病害处置。", "uncertainty_notice": "暂无已确认相似病例可交叉参考。", "recommended_actions": ["保持当前水肥和通风管理，不建议因为单次模型结果就大幅调整方案。", "保留本次图像，并在 3 到 7 天内从相同角度再拍一张做复查。", "若出现新斑点、卷叶、霉层或果实异常，应重新诊断并进行人工复核。"]}', '[{"url": "", "score": 1.05, "title": "Soybean - healthy 养护提示", "snippet": "Soybean 当前更接近健康状态。建议保持通风、稳定水肥与叶面清洁，继续观察新叶和叶背，避免在高湿环境下长期闷棚。", "evidence_id": "K59", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 1.05, "title": "Soybean 健康复查建议", "snippet": "即使模型判为健康，也建议保留原图并在 3 到 7 天内复查一次；若后续出现卷叶、斑点、霉层或颜色异常，应重新上传并结合田间环境进行判断。", "evidence_id": "K60", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.4, "title": "Apple - healthy 养护提示", "snippet": "Apple 当前更接近健康状态。建议保持通风、稳定水肥与叶面清洁，继续观察新叶和叶背，避免在高湿环境下长期闷棚。", "evidence_id": "K10", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.4, "title": "Apple 健康复查建议", "snippet": "即使模型判为健康，也建议保留原图并在 3 到 7 天内复查一次；若后续出现卷叶、斑点、霉层或颜色异常，应重新上传并结合田间环境进行判断。", "evidence_id": "K11", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}]', '2026-03-19 14:46:36', '2026-03-19 14:46:36', NULL, NULL, NULL, '未知区域', NULL, NULL);
