INSERT INTO `disease_case` (`id`, `user_id`, `prediction_record_id`, `image_filename`, `image_url`, `predicted_label`, `confirmed_label`, `crop_name`, `disease_name`, `health_status`, `confidence`, `status`, `diagnostic_summary`, `advice_json`, `evidence_json`, `created_at`, `updated_at`, `province`, `city`, `district`, `region_code`, `lat`, `lng`) VALUES (9, 12, 9, '204a7f28285c4534af0adf58a89d1ed0.JPG', '/api/static/uploads/204a7f28285c4534af0adf58a89d1ed0.JPG', 'Orange___Haunglongbing_(Citrus_greening)', 'Orange___Haunglongbing_(Citrus_greening)', 'Orange', 'Haunglongbing (Citrus greening)', 'diseased', 0.993884, 'confirmed', '当前图像更接近 Orange - Haunglongbing (Citrus greening)，模型置信度约 99.4%。', '{"summary": "当前图像更接近 Orange - Haunglongbing (Citrus greening)，模型置信度约 99.4%。", "citations": [{"title": "Orange - Haunglongbing (Citrus greening) 识别要点", "evidence_id": "K39", "source_name": "PlantCare 农业知识库"}, {"title": "Orange - Haunglongbing (Citrus greening) 初步处置", "evidence_id": "K40", "source_name": "PlantCare 农业知识库"}, {"title": "黄龙病类病害 通用建议", "evidence_id": "K41", "source_name": "PlantCare 农业知识库"}], "follow_up": "当前暂无足够相似的已确认病例，建议缩短复查周期。", "condition_overview": "Orange 疑似出现 Haunglongbing (Citrus greening)，当前建议以隔离、环境控制和复查为主。", "uncertainty_notice": "暂无已确认相似病例可交叉参考。", "recommended_actions": ["先把疑似 Haunglongbing (Citrus greening) 的叶片或植株与周边健康植株隔离观察，减少交叉传播风险。", "短期内优先调整通风、湿度和灌溉方式，避免叶面长时间潮湿。", "保留病斑扩散记录与环境信息，必要时结合人工复核再决定具体用药或处理方案。"]}', '[{"url": "", "score": 1.05, "title": "Orange - Haunglongbing (Citrus greening) 识别要点", "snippet": "Orange 出现 Haunglongbing (Citrus greening) 时，通常需要重点检查病斑扩展速度、是否伴随叶缘坏死、叶背霉层、卷曲或颜色失真，并与近期湿度、温度和灌溉情况一起判断。", "evidence_id": "K39", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 1.05, "title": "Orange - Haunglongbing (Citrus greening) 初步处置", "snippet": "建议先隔离疑似叶片，降低叶面持续潮湿时间，暂停过度喷施叶面肥，并记录拍摄日期、地块条件和扩散范围，为后续复查或人工复核提供依据。", "evidence_id": "K40", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.4, "title": "黄龙病类病害 通用建议", "snippet": "黄龙病等系统性病害具有较高风险，模型结果仅可作为筛查依据，建议优先做人工和现场综合确认。", "evidence_id": "K41", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}, {"url": "", "score": 0.3, "title": "Apple - Apple scab 识别要点", "snippet": "Apple 出现 Apple scab 时，通常需要重点检查病斑扩展速度、是否伴随叶缘坏死、叶背霉层、卷曲或颜色失真，并与近期湿度、温度和灌溉情况一起判断。", "evidence_id": "K1", "source_name": "PlantCare 农业知识库", "evidence_type": "knowledge"}]', '2026-03-19 14:50:01', '2026-03-19 14:50:01', NULL, NULL, NULL, '未知区域', NULL, NULL);
